#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, K, M; scanf("%lld %lld %lld", &N, &K, &M);
        long long cap = K * M;
        long long bags = (N + cap - 1) / cap;
        printf("%lld\n", bags);
    }
    return 0;
}

